## Implementation Structure

```typescript
// .opencode/tools/system-info.ts
import { tool } from "@opencode-ai/plugin";
import { existsSync, readFileSync } from "fs";
import { join } from "path";

export default tool({
  description: "Get runtime information about opencode-coder plugin and system status",

  args: {
    sections: tool.schema
      .array(tool.schema.string())
      .optional()
      .describe("Optional: specific sections to include (plugin, beads, github, etc)")
  },

  async execute(args, context) {
    const info = {
      metadata: {
        version: "1.0.0",
        generatedAt: new Date().toISOString()
      },

      session: {
        id: context.sessionID,
        messageId: context.messageID,
        agent: context.agent,
        pid: process.pid,
        workingDirectory: process.cwd(),
        user: process.env.USER
      },

      opencode: await getOpencodeInfo(),
      plugin: await getPluginInfo(),
      integrations: await getIntegrations(),
      knowledgeBase: await getKnowledgeBaseInfo(),
      health: await getHealthChecks()
    };

    // Filter sections if requested
    if (args.sections && args.sections.length > 0) {
      // Return only requested sections
    }

    return JSON.stringify(info, null, 2);
  }
});

async function getOpencodeInfo() {
  // Run: opencode --version
  // Check env vars: OPENCODE_DEFAULT_OPTIONS, etc.
}

async function getPluginInfo() {
  // Read package.json
  // Check .coder/coder.json
}

async function getIntegrations() {
  // Beads: bd --version, check .beads/, bd stats --json
  // GitHub: gh auth status, gh repo view --json
  // Git: git status, git branch
}

async function getKnowledgeBaseInfo() {
  // Scan knowledge-base/command/ and knowledge-base/agent/
  // Count and list them
}

async function getHealthChecks() {
  // Run same checks as /coder/doctor
  // Return structured results
